import{_ as t,c as n,o as s,ag as e}from"./chunks/framework.ELrfyV9R.js";const p="/blog/assets/output-token-cover.BB0QgpI2.jpg",b=JSON.parse('{"title":"为什么输出 Token 比输入 Token 贵？","description":"","frontmatter":{"title":"为什么输出 Token 比输入 Token 贵？","date":"2026-03-25","author":"大饶","source":"大饶不老","cover_image":"./output-token-cover.jpg","original_url":"https://mp.weixin.qq.com/s/8cUmlE4AcD4woGmdh-HHgQ"},"headers":[],"relativePath":"ai/2026-04/2026-04-23-token/why-output-token-expensive.md","filePath":"ai/2026-04/2026-04-23-token/why-output-token-expensive.md","lastUpdated":1776945928000}'),l={name:"ai/2026-04/2026-04-23-token/why-output-token-expensive.md"};function i(o,a,d,r,h,c){return s(),n("div",null,a[0]||(a[0]=[e('<h1 id="为什么输出-token-比输入-token-贵" tabindex="-1">为什么输出 Token 比输入 Token 贵？ <a class="header-anchor" href="#为什么输出-token-比输入-token-贵" aria-label="Permalink to &quot;为什么输出 Token 比输入 Token 贵？&quot;">​</a></h1><p>来源：大饶不老 作者：大饶 发布时间：2026/03/25 21:56:18 原文链接：<a href="https://mp.weixin.qq.com/s/8cUmlE4AcD4woGmdh-HHgQ" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/8cUmlE4AcD4woGmdh-HHgQ</a><img src="'+p+`" alt="cover"></p><blockquote><p>在使用 GPT-4、Claude 等大模型 API 时，你可能会发现：输出 Token 的价格往往是输入 Token 的 2-5 倍。这背后到底有什么技术原因？本文将深入剖析。</p></blockquote><h2 id="一、直观对比-价格差异有多大" tabindex="-1">一、直观对比：价格差异有多大？ <a class="header-anchor" href="#一、直观对比-价格差异有多大" aria-label="Permalink to &quot;一、直观对比：价格差异有多大？&quot;">​</a></h2><p>以主流大模型 API （非最新版本）的定价为例：</p><table tabindex="0"><thead><tr><th>模型</th><th>输入 ($/1M tokens)</th><th>输出 ($/1M tokens)</th><th>输出/输入倍数</th></tr></thead><tbody><tr><td>GPT-4</td><td>$30</td><td>$60</td><td>2x</td></tr><tr><td>Claude 3 Opus</td><td>$15</td><td>$75</td><td>5x</td></tr><tr><td>GPT-4o</td><td>$2.50</td><td>$10</td><td>4x</td></tr></tbody></table><p><strong>结论</strong>：输出 Token 的定价普遍是输入 Token 的 2-5 倍。GPT-4o输入相比GPT-4已大幅下降，但4o是推理增强模型（推理要进行多次思考输出），输出相比输入价格倍数增加了。</p><h2 id="二、核心原因-计算模式的本质差异" tabindex="-1">二、核心原因：计算模式的本质差异 <a class="header-anchor" href="#二、核心原因-计算模式的本质差异" aria-label="Permalink to &quot;二、核心原因：计算模式的本质差异&quot;">​</a></h2><h3 id="_1-输入阶段-一次性并行处理" tabindex="-1">1. 输入阶段：一次性并行处理 <a class="header-anchor" href="#_1-输入阶段-一次性并行处理" aria-label="Permalink to &quot;1. 输入阶段：一次性并行处理&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户输入: &quot;请解释量子力学&quot;</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>[一次性编码]</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>并行处理所有 Token</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>计算量: O(n²) 或 O(n)</span></span></code></pre></div><p><strong>特点</strong>：</p><ul><li><p>所有输入 Token 同时进入模型</p></li><li><p>可以高度并行化计算</p></li><li><p>只需一次完整的前向传播</p></li></ul><h3 id="_2-输出阶段-串行自回归生成" tabindex="-1">2. 输出阶段：串行自回归生成 <a class="header-anchor" href="#_2-输出阶段-串行自回归生成" aria-label="Permalink to &quot;2. 输出阶段：串行自回归生成&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>模型输出: &quot;量子&quot; → &quot;力学&quot; → &quot;是&quot; → &quot;研究&quot; → &quot;微观&quot; → ... → [结束]</span></span>
<span class="line"><span>↓ ↓ ↓ ↓ ↓</span></span>
<span class="line"><span>第1步 第2步 第3步 第4步 第5步</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每步都需要完整的前向传播！</span></span>
<span class="line"><span>计算量: O(m × n²)，其中 m = 输出长度</span></span></code></pre></div><p><strong>特点</strong>：</p><ul><li><p>必须逐个 Token 生成</p></li><li><p>每个新 Token 依赖之前所有已生成内容</p></li><li><p>无法并行，只能串行执行</p></li></ul><h2 id="三、技术原理解析" tabindex="-1">三、技术原理解析 <a class="header-anchor" href="#三、技术原理解析" aria-label="Permalink to &quot;三、技术原理解析&quot;">​</a></h2><h3 id="自回归生成的计算开销" tabindex="-1">自回归生成的计算开销 <a class="header-anchor" href="#自回归生成的计算开销" aria-label="Permalink to &quot;自回归生成的计算开销&quot;">​</a></h3><p>大语言模型采用**自回归（Autoregressive）**生成方式：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>P(x_t | x_1, x_2, ..., x_{t-1})</span></span>
<span class="line"><span></span></span>
<span class="line"><span>含义：生成第 t 个 Token 时，必须知道前面 t-1 个 Token</span></span></code></pre></div><p>这导致：</p><ul><li><p>生成长度为 100 的回复，需要执行 <strong>100 次</strong>完整的前向传播</p></li><li><p>每次都要重新计算整个上下文的注意力机制</p></li><li><p>虽然 KV Cache 能优化部分计算，但无法消除串行依赖</p></li></ul><h3 id="注意力机制的复杂度" tabindex="-1">注意力机制的复杂度 <a class="header-anchor" href="#注意力机制的复杂度" aria-label="Permalink to &quot;注意力机制的复杂度&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>标准自注意力计算复杂度: O(n² × d)</span></span>
<span class="line"><span>- n = 序列长度</span></span>
<span class="line"><span>- d = 隐藏维度</span></span>
<span class="line"><span></span></span>
<span class="line"><span>输入阶段：计算一次 Q·K^T。</span></span>
<span class="line"><span>输出阶段：每生成一个 Token 都要更新并重新计算注意力，</span></span></code></pre></div><h3 id="内存带宽瓶颈" tabindex="-1">内存带宽瓶颈： <a class="header-anchor" href="#内存带宽瓶颈" aria-label="Permalink to &quot;内存带宽瓶颈：&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────┐</span></span>
<span class="line"><span>│ 模型权重（静态，可复用）</span></span>
<span class="line"><span>│ 输入时加载一次</span></span>
<span class="line"><span>├────────────────────────┤</span></span>
<span class="line"><span>│ KV Cache（动态增长）</span></span>
<span class="line"><span>│ 每生成一个 Token 都要频繁读写</span></span>
<span class="line"><span>│ 内存带宽成为性能瓶颈</span></span>
<span class="line"><span>└────────────────────────┘</span></span></code></pre></div><p><strong>关键问题</strong>：</p><ul><li><p>现代 GPU 的算力增长快于内存带宽增长</p></li><li><p>输出阶段往往是<strong>内存带宽受限</strong>而非算力受限</p></li><li><p>频繁读写 KV Cache 导致效率降低</p></li></ul><p>（这就是PD分离背后的原因，输入是计算型，输出是频繁访存型，老两者对资源的要求不同）</p><h2 id="四、为什么无法完全并行化" tabindex="-1">四、为什么无法完全并行化？ <a class="header-anchor" href="#四、为什么无法完全并行化" aria-label="Permalink to &quot;四、为什么无法完全并行化？&quot;">​</a></h2><h3 id="_1-自回归的数学本质" tabindex="-1">1. 自回归的数学本质 <a class="header-anchor" href="#_1-自回归的数学本质" aria-label="Permalink to &quot;1. 自回归的数学本质&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原因：条件概率的链式依赖</span></span>
<span class="line"><span>P(x_1, x_2, ..., x_m) = P(x_1) × P(x_2|x_1) × P(x_3|x_1,x_2) × ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每个 Token 的生成必须等待前一个完成</span></span></code></pre></div><h3 id="_2-采样策略的多样性" tabindex="-1">2. 采样策略的多样性 <a class="header-anchor" href="#_2-采样策略的多样性" aria-label="Permalink to &quot;2. 采样策略的多样性&quot;">​</a></h3><table tabindex="0"><thead><tr><th>策略</th><th>说明</th><th>并行难度</th></tr></thead><tbody><tr><td>Greedy</td><td>每步取概率最高的 Token</td><td>低</td></tr><tr><td>Sampling</td><td>按概率分布随机采样</td><td>中</td></tr><tr><td>Beam Search</td><td>维护多个候选序列</td><td>高</td></tr></tbody></table><p>不同的采样策略增加了并行化的复杂度。</p><h3 id="_3-动态停止条件" tabindex="-1">3. 动态停止条件 <a class="header-anchor" href="#_3-动态停止条件" aria-label="Permalink to &quot;3. 动态停止条件&quot;">​</a></h3><ul><li>模型不知道何时应该生成结束标记 <code>[EOS]</code></li><li>无法预先分配计算资源</li><li>必须在运行时动态决定生成长度</li></ul><h2 id="五、时间-金钱" tabindex="-1">五、时间 = 金钱 <a class="header-anchor" href="#五、时间-金钱" aria-label="Permalink to &quot;五、时间 = 金钱&quot;">​</a></h2><h3 id="用户体验的实时性要求" tabindex="-1">用户体验的实时性要求 <a class="header-anchor" href="#用户体验的实时性要求" aria-label="Permalink to &quot;用户体验的实时性要求&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>延迟敏感度</th><th>用户感知</th></tr></thead><tbody><tr><td>输入处理</td><td>低</td><td>一次性等待</td></tr><tr><td>输出生成</td><td>高</td><td>持续感知</td></tr></tbody></table><ul><li>输入阶段：用户发送后等待，可以接受几百毫秒</li><li>输出阶段：用户看着文字<strong>逐字出现</strong>，延迟必须控制在几十毫秒内</li></ul><h3 id="批处理效率差异" tabindex="-1">批处理效率差异 <a class="header-anchor" href="#批处理效率差异" aria-label="Permalink to &quot;批处理效率差异&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入批处理：</span></span>
<span class="line"><span>┌─────┬─────┬─────┬─────┐</span></span>
<span class="line"><span>│ Q1 │ Q2 │ Q3 │ Q4 │ → 一次计算，效率极高</span></span>
<span class="line"><span>└─────┴─────┴─────┴─────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>输出批处理：</span></span>
<span class="line"><span>┌─────┐ ┌─────┐ ┌─────┐</span></span>
<span class="line"><span>│ A1 │ → │ A2 │ → │ A3 │ → 难以并行，效率低</span></span>
<span class="line"><span>└─────┘ └─────┘ └─────┘</span></span></code></pre></div><p><strong>结论</strong>：相同硬件下，输出吞吐远低于输入吞吐。</p><h2 id="六、总结" tabindex="-1">六、总结 <a class="header-anchor" href="#六、总结" aria-label="Permalink to &quot;六、总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>因素</th><th>输入 Token</th><th>输出 Token</th></tr></thead><tbody><tr><td>计算次数</td><td>1 次</td><td>N 次（N=输出长度）</td></tr><tr><td>并行度</td><td>高</td><td>低（串行依赖）</td></tr><tr><td>内存访问</td><td>少</td><td>频繁（KV Cache）</td></tr><tr><td>延迟敏感度</td><td>低</td><td>高</td></tr><tr><td>批处理效率</td><td>高</td><td>低</td></tr><tr><td>实际计算成本</td><td>基准</td><td>3-10 倍</td></tr><tr><td>API 定价倍数</td><td>1x</td><td>2-5x</td></tr></tbody></table><h2 id="七、总结" tabindex="-1">七、总结 <a class="header-anchor" href="#七、总结" aria-label="Permalink to &quot;七、总结&quot;">​</a></h2><blockquote><p><strong>输入是&quot;一次性阅读&quot;，输出是&quot;逐字手写&quot;。</strong> 后者需要反复思考、动笔、检查，自然更耗时、更耗资源、更贵。</p></blockquote><p>大模型 API 对输出 Token 收取 2-5 倍于输入 Token 的费用，实际上已经是一个<strong>优惠后的价格</strong> —— 真实的计算成本差异可能高达 3-10 倍。</p><hr><p>北七家 未来科学城 3.25</p>`,51)]))}const k=t(l,[["render",i]]);export{b as __pageData,k as default};
